const h=1;function i(r){return String(r||"").trim().toUpperCase()}function s(r){const t=i(r);return t?/^[A-Z0-9]{1,12}$/.test(t)?"":"Mã Người dùng chỉ gồm chữ A-Z và số, tối đa 12 ký tự.":"Thiếu Mã Người dùng."}function c(r){return String(r||"").trim().toUpperCase()}function a(r){const t=c(r);return t?/^[A-Z]{3}[0-9]{3}$/.test(t)?"":"Mã khách phải gồm đúng 3 chữ cái in hoa và 3 chữ số.":"Khách hàng chưa có Mã khách."}function E(r,t,u){const o=s(r);if(o)throw new Error(o);const e=a(t);if(e)throw new Error(e);const n=Number(u);if(!Number.isInteger(n)||n<1)throw new Error("Số thứ tự đơn phải bắt đầu từ 0001.");return`${i(r)}-${c(t)}-${String(n).padStart(4,"0")}`}export{h as O,i as a,E as b,a as c,c as n,s as u};
